import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import {
  Typography,
  Card,
  Table,
  Tag,
  Button,
  Space,
  theme,
  Modal,
  Form,
  Input,
  Select,
  InputNumber,
  message,
  Divider,
  Flex,
  Progress,
  Tabs,
  List,
  Badge,
  Row,
  Col
} from "antd";
import {
  PlusOutlined,
  SearchOutlined,
  EditOutlined,
  DeleteOutlined,
  FilterOutlined,
  FileTextOutlined,
  ExclamationCircleOutlined,
  CloudDownloadOutlined,
  ControlOutlined,
  BellOutlined,
  ReloadOutlined,
  CaretRightOutlined,
  DisconnectOutlined,
  InfoCircleOutlined,
  SettingOutlined,
  CloseOutlined
} from "@ant-design/icons";

const { Text, Title } = Typography;
const { confirm } = Modal;

const AssetManagementPage: React.FC = () => {
  const { t } = useTranslation(["quarantine", "management", "common"]);
  const { token } = theme.useToken();
  const [selectedGroupKeys, setSelectedGroupKeys] = useState<React.Key[]>(["tunnel"]);
  const [selectedDeviceKeys, setSelectedDeviceKeys] = useState<React.Key[]>([]);

  // Utility States
  const [showGroupSearch, setShowGroupSearch] = useState(false);
  const [groupSearchKeyword, setGroupSearchKeyword] = useState("");
  const [showDeviceSearch, setShowDeviceSearch] = useState(false);
  const [deviceSearchKeyword, setDeviceSearchKeyword] = useState("");

  // Modal States
  const [isGroupModalOpen, setIsGroupModalOpen] = useState(false);
  const [isDeviceModalOpen, setIsDeviceModalOpen] = useState(false);
  const [isControlModalOpen, setIsControlModalOpen] = useState(false);
  const [isAlarmModalOpen, setIsAlarmModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState<"add" | "edit">("add");
  const [selectedDevice, setSelectedDevice] = useState<any>(null);
  const [editingAlarm, setEditingAlarm] = useState<any>(null);
  const [alarmActiveTab, setAlarmActiveTab] = useState("list");

  // [HELP] Alarm Data Mock
  const [alarms] = useState([
    { id: 1, type: 'Temp', value: '37.5', interval: '5', status: 'ON' },
    { id: 2, type: 'Battery', value: '20', interval: '10', status: 'ON' },
    { id: 3, type: 'Access', value: 'Unauthorized', interval: '0', status: 'OFF' },
  ]);

  const [groupForm] = Form.useForm();
  const [deviceForm] = Form.useForm();
  const [alarmForm] = Form.useForm();

  // Mock Active Data
  const [groups] = useState([
    { key: "tunnel", code: "tunnel", name: "방역터널", method: "API", collectionNm: "A System", controlNm: "살균조명, 에어샤워, FFU..." },
    { key: "unmanned", code: "unmanned", name: "시설물 무인 방역장치", method: "API", collectionNm: "A System", controlNm: "살균조명, 이동..." },
    { key: "baggage", code: "baggage", name: "수화물 자동 소독장치", method: "API", collectionNm: "A System", controlNm: "살균조명, LED..." },
    { key: "disinfectionRobot", code: "disinfectionRobot", name: "방역로봇", method: "MQTT", collectionNm: "B 사이트", controlNm: "충전, 이동..." },
  ]);

  const [activeScenario] = useState({ progress: 65 });

  const filteredGroups = groups.filter(g =>
    g.name.toLowerCase().includes(groupSearchKeyword.toLowerCase()) ||
    g.code.toLowerCase().includes(groupSearchKeyword.toLowerCase())
  );

  const [devices] = useState<Record<string, any[]>>({
    "tunnel": [
      { key: "tunnelA", status: "on", code: "tunnelA", name: "방역터널A", mac: "tunnelA", alarms: 3, remarks: "" },
      { key: "tunnelB", status: "on", code: "tunnelB", name: "방역터널B", mac: "tunnelB", alarms: 0, remarks: "" },
      { key: "tunnelC", status: "on", code: "tunnelC", name: "방역터널C", mac: "tunnelC", alarms: 0, remarks: "" }
    ],
    "unmanned": [
      { key: "un-01", status: "on", code: "un-01", name: "무인장치01", mac: "00:1A:2B", alarms: 1, remarks: "정상" }
    ]
  });

  const getFilteredDevices = (groupKey: string) => {
    const list = devices[groupKey] || [];
    return list.filter(d =>
      d.name.toLowerCase().includes(deviceSearchKeyword.toLowerCase()) ||
      d.code.toLowerCase().includes(deviceSearchKeyword.toLowerCase())
    );
  };

  // Action Handlers
  const handleGroupAction = (mode: "add" | "edit", record?: any) => {
    setModalMode(mode);
    if (mode === "edit") {
      const group = record || groups.find(g => g.key === selectedGroupKeys[0]);
      groupForm.setFieldsValue(group);
    } else {
      groupForm.resetFields();
    }
    setIsGroupModalOpen(true);
  };

  const handleDeviceAction = (mode: "add" | "edit") => {
    setModalMode(mode);
    if (mode === "edit") {
      const device = devices[selectedGroupKeys[0] as string]?.find(d => d.key === selectedDeviceKeys[0]);
      deviceForm.setFieldsValue(device);
    } else {
      deviceForm.resetFields();
    }
    setIsDeviceModalOpen(true);
  };

  const handleDelete = (type: 'group' | 'device') => {
    confirm({
      title: t("common:confirmDelete"),
      icon: <ExclamationCircleOutlined />,
      content: t("common:deleteWarning"),
      okText: t("common:yes"),
      cancelText: t("common:no"),
      onOk() {
        message.success(t("common:deleteSuccess"));
      },
    });
  };

  const handleRefresh = () => {
    const hide = message.loading(t("management:refresh") + "...", 0);
    setTimeout(() => {
      hide();
      message.success(t("management:cmdSent"));
    }, 800);
  };

  const groupColumns = [
    { title: t("management:deviceGroupCode"), dataIndex: "code", key: "code", render: (val: string) => <Text className="font-mono" style={{ color: token.colorTextDescription, fontSize: 13 }}>{val}</Text> },
    { title: t("management:deviceGroupName"), dataIndex: "name", key: "name", render: (val: string) => <Text style={{ color: token.colorText, fontWeight: "bold", fontSize: 13 }}>{val}</Text> },
    { title: t("management:collectionMethod"), dataIndex: "method", key: "method", render: (val: string) => <Tag style={{ background: `${token.colorPrimary}15`, color: token.colorPrimary, fontSize: 11, fontWeight: "bold" }} variant="filled">{val}</Tag> },
    { title: t("management:collectionName"), dataIndex: "collectionNm", key: "collectionNm", render: (val: string) => <Text style={{ color: token.colorTextDescription, fontSize: 12 }}>{val}</Text> },
    {
      title: t("management:controlName"), dataIndex: "controlNm", key: "controlNm", width: 160, render: (val: string) => (
        <Select
          size="small"
          variant="borderless"
          className="w-full text-xs font-semibold custom-select-transparent"
          defaultValue={val.split(',')[0].trim()}
          options={val.split(',').map(item => ({ label: item.trim(), value: item.trim() }))}
          style={{ color: token.colorTextQuaternary }}
        />
      )
    },
    { title: "", key: "more", render: () => <Text style={{ color: token.colorTextQuaternary }}>...</Text> }
  ];

  const deviceColumns = [
    { title: t("quarantine:common.status"), dataIndex: "status", key: "status", align: "center" as const, render: (s: string) => <Tag color="success" variant="filled" style={{ fontSize: 10, fontWeight: "bold" }}>{s.toUpperCase()}</Tag> },
    { title: t("management:deviceCode"), dataIndex: "code", key: "code", render: (val: string) => <Text className="font-mono" style={{ color: token.colorTextDescription, fontSize: 13 }}>{val}</Text> },
    { title: t("management:deviceName"), dataIndex: "name", key: "name", render: (val: string) => <Text style={{ color: token.colorText, fontWeight: "bold", fontSize: 13 }}>{val}</Text> },
    { title: t("management:mac"), dataIndex: "mac", key: "mac", render: (val: string) => <Text style={{ color: token.colorTextDescription, fontSize: 12 }}>{val}</Text> },
    {
      title: t("management:registerAlarmCount"),
      dataIndex: "alarms",
      key: "alarms",
      align: "center" as const,
      render: (val: number, record: any) => (
        <Button
          type="link"
          size="small"
          className="font-bold p-0"
          style={{ color: token.colorPrimary, fontSize: 13 }}
          onClick={() => { setSelectedDevice(record); setIsAlarmModalOpen(true); }}
        >
          {val}
        </Button>
      )
    },
    { title: t("management:remarks"), dataIndex: "remarks", key: "remarks", render: (val: string) => <Text style={{ color: token.colorTextQuaternary, fontSize: 12 }}>{val}</Text> }
  ];

  return (
    <div className="h-full p-6 overflow-hidden flex flex-col relative" style={{ background: token.colorBgLayout, color: token.colorText }}>
      <Title level={4} className="font-bold mb-6" style={{ color: token.colorText }}>{t("quarantine:navigation.assetMng")}</Title>

      <div className="flex-1 grid grid-cols-2 gap-6 overflow-hidden">
        {/* Left: Equipment Group */}
        <Card
          className="flex flex-col border-none shadow-sm"
          style={{ background: token.colorBgContainer, border: `1px solid ${token.colorBorderSecondary}`, borderRadius: 12 }}
          styles={{ body: { padding: 0, height: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden' } }}
        >
          <div className="p-4 flex justify-between items-center" style={{ background: token.colorFillAlter, borderBottom: `1px solid ${token.colorBorderSecondary}` }}>
            <Space size="middle">
              <Text className="font-bold uppercase" style={{ color: token.colorTextDescription, fontSize: 12 }}>{t("management:deviceGroup")}</Text>
              <Space size={2} className="p-0.5 px-2 rounded-lg border transition-all" style={{ background: token.colorBgLayout, borderColor: token.colorBorderSecondary }}>
                <Button type="text" size="small" icon={<SearchOutlined />} className="btn-utility" onClick={() => setShowGroupSearch(!showGroupSearch)} />
                <Button type="text" size="small" icon={<FileTextOutlined />} className="btn-utility" onClick={() => message.success(t("quarantine:navigation.reportGenerated"))} />
              </Space>
              {showGroupSearch && (
                <Input
                  size="small"
                  placeholder={t("quarantine:navigation.searchPlaceholder")}
                  className="animate-in fade-in slide-in-from-left-2"
                  style={{ width: 120, borderRadius: 6, background: 'rgba(0,0,0,0.2)' }}
                  value={groupSearchKeyword}
                  onChange={(e) => setGroupSearchKeyword(e.target.value)}
                  autoFocus
                />
              )}
            </Space>
            <Divider orientation="vertical" />
            <Space size="small">
              {[
                { label: t("management:refresh"), icon: <ReloadOutlined />, className: "btn-vibrant-primary", onClick: handleRefresh },
                { label: t("management:add"), icon: <PlusOutlined />, className: "btn-vibrant-primary", onClick: () => handleGroupAction("add") },
                { label: t("management:edit"), icon: <EditOutlined />, className: "btn-vibrant-primary", onClick: () => handleGroupAction("edit") },
                { label: t("management:delete"), icon: <DeleteOutlined />, className: "btn-vibrant-secondary", onClick: () => handleDelete('group') },
              ].map(btn => (
                <Button
                  key={btn.label}
                  className={`${btn.className || "btn-vibrant-primary"} border-none h-8 px-4`}
                  icon={btn.icon}
                  onClick={(btn as any).onClick}
                >
                  {btn.label}
                </Button>
              ))}
            </Space>
          </div>
          <div className="flex-1 overflow-auto custom-scrollbar">
            <Table
              rowSelection={{ type: 'checkbox', selectedRowKeys: selectedGroupKeys, onChange: (k) => setSelectedGroupKeys(k) }}
              columns={groupColumns}
              dataSource={filteredGroups}
              pagination={false}
              size="small"
              onRow={(record) => ({ onClick: () => setSelectedGroupKeys([record.key]) })}
              rowClassName={(record) => record.key === selectedGroupKeys[0] ? 'bg-primary/5' : ''}
            />
          </div>
        </Card>

        {/* Right: Equipment List */}
        <Card
          className="flex flex-col border-none shadow-sm"
          style={{ background: token.colorBgContainer, border: `1px solid ${token.colorBorderSecondary}`, borderRadius: 12 }}
          styles={{ body: { padding: 0, height: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden' } }}
        >
          <div className="p-4 flex justify-between items-center" style={{ background: token.colorFillAlter, borderBottom: `1px solid ${token.colorBorderSecondary}` }}>
            <Space size="middle">
              <Text className="font-bold uppercase" style={{ color: token.colorTextDescription, fontSize: 12 }}>{t("management:device")}</Text>
              <Space size={2} className="p-0.5 px-2 rounded-lg border transition-all" style={{ background: token.colorBgLayout, borderColor: token.colorBorderSecondary }}>
                <Button type="text" size="small" icon={<FilterOutlined />} className="btn-utility" onClick={() => message.info(t("quarantine:navigation.filterApplied"))} />
                <Button type="text" size="small" icon={<SearchOutlined />} className="btn-utility" onClick={() => setShowDeviceSearch(!showDeviceSearch)} />
                <Button type="text" size="small" icon={<FileTextOutlined />} className="btn-utility" onClick={() => message.success(t("quarantine:navigation.reportGenerated"))} />
              </Space>
              {showDeviceSearch && (
                <Input
                  size="small"
                  placeholder={t("quarantine:navigation.searchPlaceholder")}
                  className="animate-in fade-in slide-in-from-left-2"
                  style={{ width: 120, borderRadius: 6, background: 'rgba(0,0,0,0.2)' }}
                  value={deviceSearchKeyword}
                  onChange={(e) => setDeviceSearchKeyword(e.target.value)}
                  autoFocus
                />
              )}
            </Space>
            <Space size={6}>
              <Button size="small" type="primary" icon={<PlusOutlined />} className="btn-vibrant-primary" onClick={() => handleDeviceAction("add")}>{t("management:add")}</Button>
              <Button size="small" icon={<EditOutlined />} className="btn-vibrant-primary" onClick={() => handleDeviceAction("edit")}>{t("management:edit")}</Button>
              <Button size="small" icon={<DeleteOutlined />} className="btn-vibrant-secondary" onClick={() => handleDelete('device')}>{t("management:delete")}</Button>
              <Button size="small" icon={<BellOutlined />} className="btn-vibrant-primary" onClick={() => setIsAlarmModalOpen(true)}>{t("management:alarm")}</Button>
            </Space>
          </div>
          <div className="flex-1 overflow-auto custom-scrollbar">
            <Table
              rowSelection={{ type: 'checkbox', selectedRowKeys: selectedDeviceKeys, onChange: (k) => setSelectedDeviceKeys(k) }}
              columns={deviceColumns}
              dataSource={getFilteredDevices(selectedGroupKeys[0] as string)}
              pagination={false}
              size="small"
              rowClassName={(record) => selectedDeviceKeys.includes(record.key) ? 'bg-primary/5' : ''}
            />
          </div>
        </Card>
      </div>

      {/* --- Modals --- */}

      {/* Group Modal (Add/Edit) */}
      <Modal
        title={<Text className="font-bold ml-2" style={{ color: token.colorText, fontSize: 18 }}>{modalMode === "add" ? t("management:addGroup") : t("management:editGroup")}</Text>}
        open={isGroupModalOpen}
        onCancel={() => setIsGroupModalOpen(false)}
        footer={(
          <Flex justify="end" gap={12} className="p-6 pt-0">
            <Button className="btn-vibrant-secondary h-11 px-10" onClick={() => setIsGroupModalOpen(false)}>
              {t("common:no")}
            </Button>
            <Button className="btn-vibrant-primary h-11 px-10" onClick={() => { message.success(t("common:saveSuccess")); setIsGroupModalOpen(false); }}>
              {t("common:yes")}
            </Button>
          </Flex>
        )}
        centered
        width={600}
        styles={{
          mask: { backdropFilter: "blur(12px)" },
          body: { padding: "32px 24px" },
          header: { padding: "24px 24px 0", marginBottom: 0 }
        }}
        closeIcon={<CloseOutlined style={{ color: token.colorTextQuaternary }} />}
      >
        <Form form={groupForm} layout="vertical" className="space-y-4">
          <Form.Item name="code" label={<Text strong style={{ color: token.colorTextSecondary }}>{t("management:deviceGroupCode")}</Text>} rules={[{ required: true }]}>
            <Input placeholder={t("management:enterGroupCode")} style={{ height: 42, background: token.colorBgLayout, borderRadius: 6 }} />
          </Form.Item>
          <Form.Item name="name" label={<Text strong style={{ color: token.colorTextSecondary }}>{t("management:deviceGroupName")}</Text>} rules={[{ required: true }]}>
            <Input placeholder={t("management:enterGroupName")} style={{ height: 42, background: token.colorBgLayout, borderRadius: 6 }} />
          </Form.Item>
          <Form.Item name="method" label={<Text strong style={{ color: token.colorTextSecondary }}>{t("management:collectionMethod")}</Text>}>
            <Select style={{ height: 42 }} options={[{ value: 'API', label: 'API' }, { value: 'MQTT', label: 'MQTT' }]} />
          </Form.Item>
          <Form.Item name="collectionNm" label={<Text strong style={{ color: token.colorTextSecondary }}>{t("management:collectionName")}</Text>}>
            <Input style={{ height: 42, background: token.colorBgLayout, borderRadius: 6 }} />
          </Form.Item>
        </Form>
      </Modal>

      {/* Device Modal (Add/Edit) */}
      <Modal
        title={<Text className="font-bold ml-2" style={{ color: token.colorText, fontSize: 18 }}>{modalMode === "add" ? t("management:addDevice") : t("management:editDevice")}</Text>}
        open={isDeviceModalOpen}
        onCancel={() => setIsDeviceModalOpen(false)}
        footer={(
          <Flex justify="end" gap={12} className="p-6 pt-0">
            <Button className="btn-vibrant-secondary h-11 px-10" onClick={() => setIsDeviceModalOpen(false)}>
              {t("common:no")}
            </Button>
            <Button className="btn-vibrant-primary h-11 px-10" onClick={() => { message.success(t("common:saveSuccess")); setIsDeviceModalOpen(false); }}>
              {t("common:yes")}
            </Button>
          </Flex>
        )}
        centered
        width={600}
        styles={{
          mask: { backdropFilter: "blur(12px)" },
          body: { padding: "32px 24px" },
          header: { padding: "24px 24px 0", marginBottom: 0 }
        }}
        closeIcon={<CloseOutlined style={{ color: token.colorTextQuaternary }} />}
      >
        <Form form={deviceForm} layout="vertical" className="space-y-4">
          <Form.Item name="code" label={<Text strong style={{ color: token.colorTextSecondary }}>{t("management:deviceCode")}</Text>} rules={[{ required: true }]}>
            <Input placeholder={t("management:enterDeviceCode")} style={{ height: 42, background: token.colorBgLayout, borderRadius: 6 }} />
          </Form.Item>
          <Form.Item name="name" label={<Text strong style={{ color: token.colorTextSecondary }}>{t("management:deviceName")}</Text>} rules={[{ required: true }]}>
            <Input placeholder={t("management:enterDeviceName")} style={{ height: 42, background: token.colorBgLayout, borderRadius: 6 }} />
          </Form.Item>
          <Form.Item name="mac" label={<Text strong style={{ color: token.colorTextSecondary }}>{t("management:mac")}</Text>}>
            <Input placeholder="00:00:00:00:00:00" style={{ height: 42, background: token.colorBgLayout, borderRadius: 6 }} />
          </Form.Item>
          <Form.Item name="remarks" label={<Text strong style={{ color: token.colorTextSecondary }}>{t("management:remarks")}</Text>}>
            <Input.TextArea rows={3} style={{ background: token.colorBgLayout, borderRadius: 6 }} />
          </Form.Item>
        </Form>
      </Modal>

      {/* Control Modal */}
      <Modal
        title={<Text className="font-bold ml-2" style={{ color: token.colorText, fontSize: 18 }}>{t("management:control")}</Text>}
        open={isControlModalOpen}
        onCancel={() => setIsControlModalOpen(false)}
        footer={(
          <Flex justify="end" className="p-6 pt-0">
            <Button className="btn-vibrant-secondary h-11 px-10" onClick={() => setIsControlModalOpen(false)}>
              {t("management:close")}
            </Button>
          </Flex>
        )}
        centered
        width={500}
        styles={{
          mask: { backdropFilter: "blur(4px)" },
          body: { padding: "0 12px" },
          header: { paddingBottom: 16, marginBottom: 0 }
        }}
        closeIcon={<CloseOutlined style={{ color: token.colorTextQuaternary }} />}
      >
        <div className="flex flex-col gap-6">
          <div className="p-6 rounded-2xl border" style={{ background: token.colorFillAlter, borderColor: token.colorBorderSecondary }}>
            <Text style={{ fontSize: 13, color: token.colorTextSecondary }}>
              {t("management:targetGroup")}: <Text strong style={{ color: token.colorPrimary, fontSize: 15 }}>{selectedGroupKeys[0]}</Text>
            </Text>
            <Flex justify="space-between" align="center" className="mt-4">
              <Text style={{ color: token.colorTextDescription }}>{t("quarantine:common.status")} - <Text strong style={{ color: token.colorSuccess }}>ACTIVE</Text></Text>
              <Text strong style={{ color: token.colorPrimary }}>{activeScenario.progress}%</Text>
            </Flex>
            <Progress percent={activeScenario.progress} size="small" showInfo={false} strokeColor={token.colorPrimary} trailColor="rgba(255,255,255,0.05)" className="mt-2" />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Button type="primary" block icon={<ControlOutlined />} className="btn-vibrant-primary h-14" onClick={() => message.success(t("management:cmdSent"))}>
              {t("management:powerOn")}
            </Button>
            <Button block className="btn-vibrant-danger h-14" onClick={() => message.success(t("management:cmdSent"))}>
              {t("management:powerOff")}
            </Button>
            <Button block className="btn-vibrant-secondary h-14" onClick={() => message.info(t("management:cmdSent"))}>
              {t("management:resetState")}
            </Button>
            <Button block icon={<SearchOutlined />} className="btn-vibrant-info h-14" onClick={() => message.info(t("management:cmdSent"))}>
              {t("management:runAnalysis")}
            </Button>
          </div>
        </div>
      </Modal>

      {/* Alarm Modal */}
      <Modal
        title={<Text className="font-bold ml-2" style={{ color: token.colorText, fontSize: 18 }}>{t("management:alarmSettings")}</Text>}
        open={isAlarmModalOpen}
        onCancel={() => setIsAlarmModalOpen(false)}
        footer={(
          <Flex justify="end" gap={12} className="p-6 pt-0">
            <Button className="btn-vibrant-secondary h-11 px-10" onClick={() => setIsAlarmModalOpen(false)}>
              {t("common:no")}
            </Button>
            <Button className="btn-vibrant-primary h-11 px-10" onClick={() => { message.success(t("common:saveSuccess")); setIsAlarmModalOpen(false); }}>
              {t("common:yes")}
            </Button>
          </Flex>
        )}
        centered
        width={500}
        styles={{
          mask: { backdropFilter: "blur(12px)" },
          body: { padding: "32px 24px" },
          header: { padding: "24px 24px 0", marginBottom: 0 }
        }}
        closeIcon={<CloseOutlined style={{ color: token.colorTextQuaternary }} />}
      >
        <Form layout="vertical" className="space-y-6">
          <Form.Item label={<Text strong style={{ color: token.colorTextSecondary }}>{t("management:tempThreshold")}</Text>}>
            <InputNumber style={{ width: '100%', height: 42 }} defaultValue={37.5} />
          </Form.Item>
          <Form.Item label={<Text strong style={{ color: token.colorTextSecondary }}>{t("management:alarmInterval")}</Text>}>
            <InputNumber style={{ width: '100%', height: 42 }} defaultValue={30} />
          </Form.Item>
        </Form>
      </Modal>

      <style>{`
        .ant-table-wrapper { height: 100%; }
        .ant-table { background: transparent !important; color: ${token.colorText} !important; border-top: 1px solid ${token.colorBorderSecondary} !important; }
        .ant-table-thead > tr > th { 
           background: ${token.colorFillAlter} !important; 
           color: ${token.colorTextSecondary} !important; 
           font-size: 11px !important; 
           font-weight: 900 !important; 
           border-bottom: 2px solid ${token.colorBorderSecondary} !important;
           text-align: center !important;
           padding: 12px 8px !important;
        }
        .ant-table-tbody > tr > td { 
           border-bottom: 1px solid ${token.colorBorderSecondary} !important; 
           text-align: center !important; 
           padding: 10px 8px !important; 
           font-size: 13px; 
           background: transparent !important;
        }
        .ant-table-row:hover > td { background: ${token.colorFillAlter} !important; cursor: pointer; }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.05); border-radius: 10px; }

        /* Solid Button System (High Contrast & Unified Blue - Per User Screenshot) */
        .btn-vibrant-primary, .btn-vibrant-secondary, .btn-vibrant-danger, .btn-vibrant-info, .btn-vibrant-warning { 
          background: ${token.colorPrimary} !important; 
          border-color: ${token.colorPrimary} !important; 
          color: #fff !important; 
          font-weight: bold !important; 
          border-radius: 6px !important; 
          transition: all 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275);
        }

        .btn-vibrant-primary:hover {
          filter: brightness(1.1) saturate(1.1);
          box-shadow: 0 4px 12px ${token.colorPrimary}40;
          transform: translateY(-1px);
        }
        .btn-vibrant-secondary {
          background: ${token.colorFillAlter} !important;
          border: 1px solid ${token.colorBorderSecondary} !important;
          color: ${token.colorTextDescription} !important;
          font-weight: bold !important;
          border-radius: 6px !important;
          transition: all 0.2s ease;
          display: flex;
          align-items: center;
          justify-content: center;
        }
        .btn-vibrant-secondary:hover {
          background: ${token.colorFillSecondary} !important;
          color: ${token.colorText} !important;
          border-color: ${token.colorBorder} !important;
        }

        .btn-utility {
          color: ${token.colorTextQuaternary} !important;
          padding: 0 4px !important;
          border-radius: 4px !important;
          transition: all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
        }
        .btn-utility:hover { 
          color: ${token.colorPrimary} !important; 
          background: ${token.colorPrimary}1a !important; 
          transform: scale(1.2);
          filter: drop-shadow(0 0 5px ${token.colorPrimary}40);
        }

        @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
        @keyframes slide-in-from-left-2 { from { transform: translateX(-8px); } to { transform: translateX(0); } }
        .custom-select-transparent .ant-select-selector {
          background: rgba(255, 255, 255, 0.05) !important;
          border: 1px solid rgba(255, 255, 255, 0.1) !important;
          color: rgba(255, 255, 255, 0.45) !important;
          border-radius: 4px !important;
        }
        .custom-select-transparent:hover .ant-select-selector {
          border-color: ${token.colorPrimary} !important;
          background: rgba(255, 255, 255, 0.1) !important;
        }
        .animate-in { animation: fade-in 0.3s ease-out; }
        .slide-in-from-left-2 { animation: slide-in-from-left-2 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275); }
      `}</style>
      {/* Alarm Settings Modal */}
      <Modal
        title={
          <Flex align="center" gap={8}>
            <BellOutlined style={{ color: token.colorPrimary }} />
            <Text className="font-bold" style={{ fontSize: 18 }}>
              {t("management:alarmSettings")} - {selectedDevice?.name || t("management:device")}
            </Text>
          </Flex>
        }
        open={isAlarmModalOpen}
        onCancel={() => setIsAlarmModalOpen(false)}
        width={700}
        footer={(
          <Flex justify="end" gap={12} className="p-6 pt-0">
            <Button className="btn-vibrant-secondary h-11 px-10" onClick={() => setIsAlarmModalOpen(false)}>
              {t("management:close")}
            </Button>
            <Button className="btn-vibrant-primary h-11 px-10" onClick={() => { message.success(t("management:cmdSent")); setIsAlarmModalOpen(false); }}>
              {t("management:save")}
            </Button>
          </Flex>
        )}
      >
        <Tabs
          activeKey={alarmActiveTab}
          onChange={(key) => setAlarmActiveTab(key)}
          className="custom-tabs"
          items={[
            {
              key: 'list',
              label: (
                <Space>
                  <FileTextOutlined />
                  {t("management:operationalStatus")}
                </Space>
              ),
              children: (
                <List
                  className="mt-2"
                  dataSource={alarms}
                  renderItem={(item) => (
                    <List.Item
                      actions={[
                        <Button type="link" size="small" onClick={() => { setEditingAlarm(item); setAlarmActiveTab("edit"); }}>{t("management:edit")}</Button>
                      ]}
                    >
                      <List.Item.Meta
                        avatar={<Badge status={item.status === 'ON' ? 'processing' : 'default'} />}
                        title={<Text strong>{item.type}</Text>}
                        description={
                          <Space split={<Divider orientation="vertical" />}>
                            <Text style={{ fontSize: 12 }}>{t("management:tempThreshold")}: {item.value}</Text>
                            <Text style={{ fontSize: 12 }}>{t("management:alarmInterval")}: {item.interval}{t("management:seconds")}</Text>
                          </Space>
                        }
                      />
                    </List.Item>
                  )}
                />
              )
            },
            {
              key: 'edit',
              label: (
                <Space>
                  <SettingOutlined />
                  {t("management:edit")}
                </Space>
              ),
              children: (
                <div className="p-4">
                  <Form
                    form={alarmForm}
                    layout="vertical"
                    initialValues={editingAlarm || alarms[0]}
                  >
                    <Row gutter={16}>
                      <Col span={12}>
                        <Form.Item name="type" label={t("management:type")}>
                          <Select options={alarms.map(a => ({ label: a.type, value: a.type }))} />
                        </Form.Item>
                      </Col>
                      <Col span={12}>
                        <Form.Item name="status" label={t("management:opStatus")}>
                          <Select options={[{ label: t("quarantine:common.online"), value: 'ON' }, { label: t("quarantine:common.offline"), value: 'OFF' }]} />
                        </Form.Item>
                      </Col>
                    </Row>
                    <Row gutter={16}>
                      <Col span={12}>
                        <Form.Item name="value" label={t("management:tempThreshold")}>
                          <Input suffix="°C / %" />
                        </Form.Item>
                      </Col>
                      <Col span={12}>
                        <Form.Item name="interval" label={t("management:alarmInterval")}>
                          <InputNumber className="w-full" suffix={t("management:seconds")} />
                        </Form.Item>
                      </Col>
                    </Row>
                  </Form>
                </div>
              )
            }
          ]}
        />
      </Modal>
    </div>
  );
};

export default AssetManagementPage;
